function mkClouds(){
  const TW=isLow?1024:2048,TH=isLow?512:1024;
  const cv=document.createElement('canvas');cv.width=TW;cv.height=TH;
  const c=cv.getContext('2d');

  // Layer 1 — high cirrus (thin, wide, angled)
  for(let i=0;i<90;i++){
    const s=i*17.31;
    const x=H2(s)*TW, y=H2(s+1)*TH;
    const rx=H2(s+2)*190+45, ry=H2(s+3)*9+3, al=H2(s+4)*.17+.02;
    const g=c.createRadialGradient(x,y,0,x,y,rx);
    g.addColorStop(0,`rgba(255,255,255,${al})`); g.addColorStop(.7,`rgba(255,255,255,${al*.18})`); g.addColorStop(1,'rgba(255,255,255,0)');
    c.save(); c.translate(x,y); c.rotate(H2(s+5)*.9-.45); c.scale(1,ry/Math.max(rx,1));
    c.beginPath(); c.arc(0,0,rx,0,Math.PI*2); c.fillStyle=g; c.fill(); c.restore();
  }

  // Layer 2-5 — mid cumulus
  for(let layer=0;layer<5;layer++){
    for(let i=0;i<70;i++){
      const s=i*13.71+layer*320;
      const x=H2(s)*TW, y=H2(s+1)*TH;
      const rx=H2(s+2)*105+24, ry=H2(s+3)*30+10, al=H2(s+4)*.44+.05;
      const g=c.createRadialGradient(x,y-ry*.18,ry*.35,x,y,rx);
      g.addColorStop(0,`rgba(255,255,255,${al})`);
      g.addColorStop(.42,`rgba(249,251,255,${al*.52})`);
      g.addColorStop(.8, `rgba(240,245,255,${al*.13})`);
      g.addColorStop(1,'rgba(255,255,255,0)');
      c.save(); c.translate(x,y); c.scale(1,ry/Math.max(rx,1));
      c.beginPath(); c.arc(0,0,rx,0,Math.PI*2); c.fillStyle=g; c.fill(); c.restore();
    }
  }

  // ITCZ — equatorial tropical cloud band
  const itz=c.createLinearGradient(0,TH*.42,0,TH*.58);
  itz.addColorStop(0,'transparent'); itz.addColorStop(.35,'rgba(255,255,255,.08)');
  itz.addColorStop(.5,'rgba(255,255,255,.13)'); itz.addColorStop(.65,'rgba(255,255,255,.08)'); itz.addColorStop(1,'transparent');
  c.fillStyle=itz; c.fillRect(0,TH*.42,TW,TH*.16);

  // Polar vortex swirls
  for(let pole=0;pole<2;pole++){
    const cy2=pole===0?TH*.10:TH*.90, cx2=TW*.5;
    for(let i=0;i<14;i++){
      const ang=i*Math.PI*2/14+pole*.5;
      const r=42+H2(i*7.31)*85;
      const x=cx2+Math.cos(ang)*r, y=cy2+Math.sin(ang)*r*.38;
      const rx=H2(i*3.13)*75+32, ry=H2(i*5.71)*22+9, al=H2(i*2.91)*.36+.05;
      c.save(); c.translate(x,y); c.rotate(ang+Math.PI*.5); c.scale(1,ry/Math.max(rx,1));
      const g=c.createRadialGradient(0,0,0,0,0,rx);
      g.addColorStop(0,`rgba(255,255,255,${al})`); g.addColorStop(1,'transparent');
      c.beginPath(); c.arc(0,0,rx,0,Math.PI*2); c.fillStyle=g; c.fill(); c.restore();
    }
  }

  // Tropical cyclones — spiral arms
  [[.120,.352],[.822,.381],[.322,.622],[.661,.552],[.481,.281]].forEach(([scx,scy],si)=>{
    const sx=scx*TW, sy=scy*TH, maxR=58+si*13;
    for(let arm=0;arm<3;arm++){
      for(let j=0;j<18;j++){
        const frac=j/17, ang=arm*Math.PI*2/3+frac*Math.PI*1.7;
        const r=frac*maxR, px=sx+Math.cos(ang)*r, py=sy+Math.sin(ang)*r*.55;
        const bR=13+frac*19, al=(1-frac)*.30+.04;
        const g=c.createRadialGradient(px,py,0,px,py,bR);
        g.addColorStop(0,`rgba(255,255,255,${al})`); g.addColorStop(1,'transparent');
        c.fillStyle=g; c.beginPath(); c.arc(px,py,bR,0,Math.PI*2); c.fill();
      }
    }
    c.save(); c.globalCompositeOperation='destination-out';
    c.beginPath(); c.arc(sx,sy,11+si*2,0,Math.PI*2);
    c.fillStyle=`rgba(0,0,0,.42)`; c.fill(); c.restore();
  });

  // Cloud undersides (subtle grey shadow)
  for(let i=0;i<55;i++){
    const s=i*23.13+500;
    const x=H2(s)*TW, y=H2(s+1)*TH+7;
    const rx=H2(s+2)*85+22, ry=H2(s+3)*19+7, al=H2(s+4)*.058;
    c.save(); c.translate(x,y); c.scale(1,ry/Math.max(rx,1));
    c.beginPath(); c.arc(0,0,rx,0,Math.PI*2);
    c.fillStyle=`rgba(178,188,208,${al})`; c.fill(); c.restore();
  }
  return new THREE.CanvasTexture(cv);
}
function mkGalaxy(){
  const TW=isLow?1024:2048,TH=isLow?512:1024;
  const cv=document.createElement('canvas');cv.width=TW;cv.height=TH;
  const c=cv.getContext('2d');

  // Deep space fill
  const bg=c.createLinearGradient(0,0,TW,TH);
  bg.addColorStop(0,'#010410'); bg.addColorStop(.3,'#020614'); bg.addColorStop(.5,'#030818');
  bg.addColorStop(.7,'#020614'); bg.addColorStop(1,'#010410');
  c.fillStyle=bg; c.fillRect(0,0,TW,TH);

  // Nebula regions (5 distinct zones)
  [{x:.22,y:.36,r:.46,c0:'rgba(5,11,66,.20)',c1:'rgba(2,16,52,.10)'},
   {x:.68,y:.58,r:.40,c0:'rgba(46,4,60,.16)',c1:'rgba(26,2,40,.08)'},
   {x:.82,y:.22,r:.36,c0:'rgba(0,36,62,.18)',c1:'rgba(0,20,46,.09)'},
   {x:.10,y:.74,r:.33,c0:'rgba(20,4,52,.14)',c1:'rgba(10,2,36,.07)'},
   {x:.50,y:.15,r:.28,c0:'rgba(0,26,50,.12)',c1:'rgba(0,14,36,.06)'},
  ].forEach(({x,y,r,c0,c1})=>{
    const nx=x*TW, ny=y*TH, nr=r*Math.min(TW,TH);
    const g=c.createRadialGradient(nx,ny,0,nx,ny,nr);
    g.addColorStop(0,c0); g.addColorStop(.6,c1); g.addColorStop(1,'transparent');
    c.fillStyle=g; c.beginPath(); c.arc(nx,ny,nr,0,Math.PI*2); c.fill();
    const g2=c.createRadialGradient(nx,ny,0,nx,ny,nr*.28);
    g2.addColorStop(0,c0); g2.addColorStop(1,'transparent');
    c.fillStyle=g2; c.beginPath(); c.arc(nx,ny,nr*.28,0,Math.PI*2); c.fill();
  });

  // Milky Way — 4 layers with dust lane
  c.save(); c.translate(TW*.5,TH*.5); c.rotate(.22);
  for(let layer=0;layer<4;layer++){
    const w=.009+layer*.007, spread=TH*(.19+layer*.07);
    const mw=c.createLinearGradient(-TW*.72,0,TW*.72,0);
    mw.addColorStop(0,'transparent'); mw.addColorStop(.20,`rgba(255,255,255,${w*.5})`);
    mw.addColorStop(.44,`rgba(255,255,255,${w})`); mw.addColorStop(.5,`rgba(255,255,255,${w*1.45})`);
    mw.addColorStop(.56,`rgba(255,255,255,${w})`); mw.addColorStop(.80,`rgba(255,255,255,${w*.5})`);
    mw.addColorStop(1,'transparent');
    c.fillStyle=mw; c.fillRect(-TW*.72,-spread,TW*1.44,spread*2);
  }
  // Dust lane
  const dust=c.createLinearGradient(-TW*.42,0,TW*.42,0);
  dust.addColorStop(0,'transparent'); dust.addColorStop(.40,'rgba(0,0,0,.08)');
  dust.addColorStop(.50,'rgba(0,0,0,.16)'); dust.addColorStop(.60,'rgba(0,0,0,.08)'); dust.addColorStop(1,'transparent');
  c.fillStyle=dust; c.fillRect(-TW*.42,-TH*.045,TW*.84,TH*.09);
  // MW scatter
  for(let i=0;i<(isLow?700:2000);i++){
    const px=(H2(i*9.31)-.5)*TW*1.25, py=(H2(i*6.13)-.5)*TH*.24;
    c.fillStyle=`rgba(255,255,255,${H2(i*3.71)*.052})`; c.fillRect(px,py,.8,.8);
  }
  c.restore();

  // Stars — 10000 with proper magnitude + spectral distribution
  const NS=isLow?4500:10000;
  for(let i=0;i<NS;i++){
    const x=H2(i*7.31)*TW, y=H2(i*11.73)*TH;
    const mag=Math.pow(H2(i*3.13),.45); // bias toward dim stars
    const sz=mag<.80?mag*.42+.09:mag<.92?mag*.95+.22:mag*2.3+.45;
    const br=mag*.74+.26;
    const t=H2(i*6.73);
    let col;
    if(t<.08)      col=`rgba(152,172,255,${br})`;
    else if(t<.18) col=`rgba(198,216,255,${br})`;
    else if(t<.42) col=`rgba(255,255,255,${br})`;
    else if(t<.64) col=`rgba(255,248,218,${br})`;
    else if(t<.81) col=`rgba(255,218,158,${br})`;
    else           col=`rgba(255,188,118,${br*.68})`;

    if(sz>1.05&&!isLow){
      const sg=c.createRadialGradient(x,y,0,x,y,sz*4.2);
      const alpha_str=br*.38;
      sg.addColorStop(0,col);
      sg.addColorStop(.45,col.replace(/[\d.]+\)$/,`${alpha_str})`));
      sg.addColorStop(1,'transparent');
      c.fillStyle=sg; c.beginPath(); c.arc(x,y,sz*4.2,0,Math.PI*2); c.fill();
      if(sz>1.65){
        c.strokeStyle=col.replace(/[\d.]+\)$/,`${br*.20})`); c.lineWidth=.55;
        [0,Math.PI*.5].forEach(ang=>{
          const len=sz*7.5;
          c.beginPath();
          c.moveTo(x+Math.cos(ang)*len*.22,y+Math.sin(ang)*len*.22);
          c.lineTo(x+Math.cos(ang)*len,y+Math.sin(ang)*len);
          c.moveTo(x-Math.cos(ang)*len*.22,y-Math.sin(ang)*len*.22);
          c.lineTo(x-Math.cos(ang)*len,y-Math.sin(ang)*len);
          c.stroke();
        });
      }
    }
    c.fillStyle=col; c.fillRect(x-.5,y-.5,sz,sz);
  }

  // Star clusters
  [[.38,.28,14,9,'rgba(178,198,255,.58)'],[.12,.52,10,7,'rgba(255,228,178,.46)'],[.74,.70,8,6,'rgba(188,208,255,.52)']].forEach(([cx,cy,n,r,col])=>{
    for(let i=0;i<n;i++){
      const sx=cx*TW+H2(i*17.31+cx*100)*r*2-r, sy=cy*TH+H2(i*13.13+cy*100)*r*2-r;
      const sg=c.createRadialGradient(sx,sy,0,sx,sy,r*.85);
      sg.addColorStop(0,col); sg.addColorStop(1,'transparent');
      c.fillStyle=sg; c.beginPath(); c.arc(sx,sy,r*.85,0,Math.PI*2); c.fill();
      c.fillStyle=col.replace(/[\d.]+\)$/,'1)'); c.fillRect(sx,sy,.85,.85);
    }
  });

  // Shooting stars
  c.strokeStyle='rgba(200,226,255,.38)'; c.lineWidth=.6;
  [[.08,.15,.26,.30],[.63,.08,.80,.17],[.14,.70,.27,.80],[.55,.42,.72,.48]].forEach(([x1,y1,x2,y2])=>{
    c.beginPath(); c.moveTo(x1*TW,y1*TH); c.lineTo(x2*TW,y2*TH); c.stroke();
  });
  return new THREE.CanvasTexture(cv);
}
/* ══════════════════════════════════════════════════
   GLSL ATMOSPHERE SHADER (Fresnel rim glow)
══════════════════════════════════════════════════ */
const atmVS=`
varying vec3 vNormal;
varying vec3 vPos;
void main(){
  vNormal=normalize(normalMatrix*normal);
  vPos=(modelViewMatrix*vec4(position,1.)).xyz;
  gl_Position=projectionMatrix*modelViewMatrix*vec4(position,1.);
}`;
const atmFS=`
uniform float uTime;
uniform float uGlow;
uniform float uPulse;
uniform float uAurora;
uniform float uOcean;
varying vec3 vNormal;
varying vec3 vPos;

// Improved Rayleigh + Mie scatter approximation
vec3 rayleigh(float cosAngle){
  // Wavelength-dependent scatter: blue > green > red
  vec3 beta=vec3(5.8e-3,1.35e-3,3.31e-4); // Rayleigh coefficients RGB
  return beta*(1.+cosAngle*cosAngle)*.75;
}

void main(){
  vec3 viewDir=normalize(-vPos);
  float ndotv=abs(dot(vNormal,viewDir));
  float rim=1.-ndotv;
  float rim2=pow(rim,2.2);
  float rim3=pow(rim,3.4);
  float rim5=pow(rim,5.5);

  // ── Rayleigh scattering ──
  // limb: scatter path length ∝ 1/cos(θ) — much longer at edge
  float scatter=pow(rim,1.3)*.88 + rim5*.14;
  vec3 dayBlue=vec3(.05,.34,.92);
  vec3 horizonGlow=vec3(.88,.52,.08); // orange-red at horizon (sunset-like)
  vec3 horizonBlue=vec3(.38,.62,.96); // blue near terminator
  vec3 scatterCol=mix(mix(dayBlue,horizonBlue,rim2*.65),horizonGlow,pow(rim5,.28)*.68);

  float pulse=sin(uTime*1.4)*.062;
  float glowFactor=rim2*uGlow*(1.+pulse+uPulse*.42);

  // Inner atmosphere body
  vec3 inner=vec3(.022,.14,.68);
  vec3 outer=vec3(.04,.52,.98);
  vec3 col=mix(inner,outer,pow(rim,1.5));

  // Blend in Rayleigh scatter toward limb
  col=mix(col,scatterCol,rim3*.58);

  // ── Stratospheric layers (thin bands) ──
  float strat=sin(vNormal.y*10.+uTime*.68)*.022+sin(vNormal.y*18.+uTime*.44)*.010;
  col+=vec3(.0,strat*.42,strat);

  // ── Equatorial airglow / ionospheric luminescence ──
  float eq=pow(1.-abs(vNormal.y)*.96,8.)*.28;
  vec3 airglow=vec3(.02,.06,.18);
  col+=airglow*eq*uGlow;

  // ── Polar aurora — multi-wavelength emission ──
  float absLat=abs(vNormal.y);
  // Only above ~52° latitude (magnetic oval)
  float pole=pow(max(0.,(absLat-.50)*2.8),1.8);
  float aW1=sin(vNormal.x*12.+uTime*2.8)*.5+.5;
  float aW2=sin(vNormal.z*9.+uTime*2.0+1.5)*.5+.5;
  float aW3=sin(vNormal.x*5.+vNormal.z*7.+uTime*1.3+2.2)*.5+.5;
  float aW4=sin(vNormal.y*8.+uTime*1.8+.8)*.5+.5;
  // OI 557.7nm (green), N2 427.8nm (blue-violet), OI 630nm (red/orange above)
  vec3 aGreen=vec3(.0,.96,.38);   // 557nm O
  vec3 aPurp= vec3(.52,.0,.98);   // 427nm N2
  vec3 aCyan= vec3(.0,.78,.98);   // 486nm H
  vec3 aRed=  vec3(.88,.22,.04);  // 630nm O (high altitude)
  vec3 aCol=mix(mix(aGreen,aPurp,aW1),mix(aCyan,aRed,aW4*.4),aW2*aW3*.52);
  float aStr=pole*uAurora*rim2*(0.84+sin(uTime*1.3+vNormal.x*6.)*.16);

  // Aurora curtain shimmer (vertical striations)
  float curtain=sin(vNormal.x*28.+uTime*6.+vNormal.z*14.)*.5+.5;
  aStr*=(0.72+curtain*.28);

  col=mix(col,aCol,min(aStr*.86,.92));

  // ── Ocean floor signal (Chapter III) ──
  float oceanLat=pow(1.-abs(vNormal.y+.14)*.84,4.2);
  float oceanLon=pow(max(0.,-vNormal.x*.58+.42),2.2);
  vec3 oceanCol=vec3(.0,.74,.60);
  float oceanStr=oceanLat*oceanLon*uOcean;
  col=mix(col,oceanCol,oceanStr*.58);

  // ── Final alpha ──
  float alpha=rim2*.48*uGlow + aStr*.38 + oceanStr*.26 + rim5*.18;
  // Thin outer glow ring
  alpha+=rim5*.08*uGlow;

  gl_FragColor=vec4(col*glowFactor + aCol*aStr*.24 + oceanCol*oceanStr*.16, min(alpha,1.0));
}`;

const atmMat=new THREE.ShaderMaterial({
  uniforms:{uTime:{value:0},uGlow:{value:1.3},uPulse:{value:0},uAurora:{value:0.0},uOcean:{value:0.0}},
  vertexShader:atmVS,fragmentShader:atmFS,
  transparent:true,side:THREE.BackSide,depthWrite:false
});

/* GLSL Halo (outer glow) */
const haloFS=`
uniform float uTime;
uniform float uGlow;
varying vec3 vNormal;
varying vec3 vPos;
void main(){
  vec3 viewDir=normalize(-vPos);
  float ndotv=abs(dot(vNormal,viewDir));
  float rim=1.-ndotv;
  float rim4=pow(rim,4.2);
  float rim6=pow(rim,6.5);
  float pulse=sin(uTime*0.68)*0.038;
  // Blue dominant outer glow, sunset ring at extreme limb
  vec3 blueGlow=mix(vec3(.0,.55,.95),vec3(.02,.38,.88),vNormal.y*.5+.5);
  vec3 sunsetRing=vec3(.72,.42,.06);
  vec3 col=mix(blueGlow,sunsetRing,rim6*.42);
  float pole=pow(abs(vNormal.y),.9)*.15;
  col+=vec3(.0,.06,.16)*pole;
  gl_FragColor=vec4(col,rim4*.28*uGlow*(1.+pulse)+rim6*.10);
}`;
const haloMat=new THREE.ShaderMaterial({
  uniforms:{uTime:{value:0},uGlow:{value:1.0}},
  vertexShader:atmVS,fragmentShader:haloFS,
  transparent:true,side:THREE.BackSide,depthWrite:false
});

/* ══════════════════════════════════════════════════
   BUILD EARTH MODEL
══════════════════════════════════════════════════ */
const galaxyTex=mkGalaxy();
galaxyTex.minFilter=THREE.LinearMipmapLinearFilter;
galaxyTex.magFilter=THREE.LinearFilter;
galaxyTex.generateMipmaps=true;
if('encoding' in galaxyTex)galaxyTex.encoding=THREE.sRGBEncoding;
scene.background=galaxyTex;

// Earth sphere — high tessellation
const earthGeo=new THREE.SphereGeometry(2,isLow?64:isMid?128:256,isLow?64:isMid?128:256);
// Bump map — land/mtn/ice height approximation for surface relief
function mkBump(){
  const TW=isLow?512:1024,TH=isLow?256:512;
  const cv=document.createElement('canvas');cv.width=TW;cv.height=TH;
  const c=cv.getContext('2d');

  // Ocean baseline — mid-grey (flat)
  c.fillStyle='#444'; c.fillRect(0,0,TW,TH);

  // Real-world landmask gives global-scale relief placement
  paintGeoBump(c,TW,TH);

  function bB(cx,cy,rx,ry,rot,col,edgeCol){
    c.save(); c.translate(cx*TW,cy*TH); c.rotate(rot||0); c.scale(1,ry/Math.max(rx,1));
    const g=c.createRadialGradient(0,0,rx*.25,0,0,rx);
    g.addColorStop(0,col); g.addColorStop(.75,edgeCol||col); g.addColorStop(1,'transparent');
    c.beginPath(); c.arc(0,0,rx,0,Math.PI*2); c.fillStyle=g; c.fill(); c.restore();
  }

  // Land (slightly raised — mid-light grey)
  [[.172,.316,78,52,-.24],[.158,.355,42,30,-.12],[.220,.548,45,68,.05],
   [.575,.284,46,33,-.20],[.586,.188,13,32,-.12],[.610,.328,36,22,.14],
   [.600,.425,52,30,.00],[.614,.524,36,32,.06],[.660,.282,88,55,-.08],
   [.728,.256,52,36,.10],[.693,.458,28,36,.00],[.814,.618,46,32,.16],
   [.870,.526,18,12,.06],
  ].forEach(([cx,cy,rx,ry,rot])=>bB(cx,cy,rx,ry,rot,'#747474','#686868'));

  // Mountain ranges — significantly raised (bright)
  // Rockies
  bB(.132,.332,10,28,-.18,'#c4c4c4','#aaaaaa');
  // Andes
  bB(.208,.566,6,55,-.05,'#cccccc','#b4b4b4');
  // Alps
  bB(.591,.296,14,8,-.10,'#c0c0c0','#a8a8a8');
  // Himalayas (highest range)
  bB(.700,.400,48,11,-.03,'#e0e0e0','#cccccc');
  // Tibetan Plateau (high but relatively flat)
  bB(.735,.400,36,14,.02,'#b8b8b8','#a4a4a4');
  // Ethiopian Highlands
  bB(.646,.476,12,14,.04,'#a8a8a8','#989898');
  // Atlas Mountains
  bB(.592,.402,14,8,.14,'#a8a8a8','#969696');
  // Scandinavian fjeld
  bB(.586,.188,10,28,-.12,'#9c9c9c','#8c8c8c');
  // Great Dividing Range
  bB(.848,.618,5,26,-.12,'#9e9e9e','#8e8e8e');
  // Pyrenees / Apennines
  bB(.571,.314,8,5,-.05,'#a4a4a4','#949494');
  bB(.612,.342,10,18,.16,'#a0a0a0','#909090');
  // Caucasus
  bB(.642,.312,12,6,.08,'#a8a8a8','#989898');
  // Urals
  bB(.664,.240,5,28,.04,'#8c8c8c','#7c7c7c');

  // Ocean trenches — very dark (deep)
  // Mariana Trench area
  bB(.830,.450,16,4,.14,'#202020','#303030');
  // Mid-Atlantic Ridge (slightly raised)
  bB(.370,.500,4,55,.02,'#545454','#4c4c4c');

  // Ice caps — slightly raised
  const iT=c.createLinearGradient(0,0,0,TH*.15);
  iT.addColorStop(0,'#888'); iT.addColorStop(1,'transparent');
  c.fillStyle=iT; c.fillRect(0,0,TW,TH*.15);
  const iB=c.createLinearGradient(0,TH*.83,0,TH);
  iB.addColorStop(0,'transparent'); iB.addColorStop(1,'#888');
  c.fillStyle=iB; c.fillRect(0,TH*.83,TW,TH*.17);

  // Noise for terrain roughness
  for(let i=0;i<2000;i++){
    const x=H2(i*7.31)*TW, y=H2(i*11.73)*TH;
    const v=(H2(i*3.71)-.5)*.04;
    c.fillStyle=`rgba(${128+(v*255)|0},${128+(v*255)|0},${128+(v*255)|0},.18)`;
    c.fillRect(x,y,1,1);
  }

  return new THREE.CanvasTexture(cv);
}
const dayTex=mkDay();
const nightTex=mkNight();
const specTex=mkSpec();
const bumpTex=mkBump();
const maxAniso=Math.min(8,(ren.capabilities&&ren.capabilities.getMaxAnisotropy)?ren.capabilities.getMaxAnisotropy():1);
function tuneTex(t,{srgb=false}={}){
  t.wrapS=t.wrapT=THREE.RepeatWrapping;
  t.minFilter=THREE.LinearMipmapLinearFilter;
  t.magFilter=THREE.LinearFilter;
  t.generateMipmaps=true;
  t.anisotropy=maxAniso;
  if(srgb&&'encoding' in t)t.encoding=THREE.sRGBEncoding;
  t.needsUpdate=true;
}
tuneTex(dayTex,{srgb:true});
tuneTex(nightTex,{srgb:true});
tuneTex(specTex);
tuneTex(bumpTex);

const earthMat=new THREE.MeshPhongMaterial({
  map:dayTex,
  emissiveMap:nightTex,
  emissive:new THREE.Color(1.0,.98,1.0),
  emissiveIntensity:.80,// city glow on night side
  specularMap:specTex,
  specular:new THREE.Color(.22,.35,.62),// ocean glint, realistic blue-white
  shininess:160,// polished ocean surface
  bumpMap:bumpTex,
  bumpScale:0.022,// stronger terrain relief
});
const earth=new THREE.Mesh(earthGeo,earthMat);
earth.rotation.z=23.5*(Math.PI/180);// axial tilt
scene.add(earth);

// Main atmosphere shell
const atm=new THREE.Mesh(new THREE.SphereGeometry(2.26,isLow?48:128,isLow?48:128),atmMat);
scene.add(atm);

// Inner soft glow
const inner=new THREE.Mesh(
  new THREE.SphereGeometry(2.07,64,64),
  new THREE.MeshPhongMaterial({color:0x0038bb,emissive:0x001e7a,emissiveIntensity:.9,transparent:true,opacity:.09,side:THREE.FrontSide,depthWrite:false})
);
scene.add(inner);

// Outer halo (much larger, very subtle)
const halo=new THREE.Mesh(new THREE.SphereGeometry(2.58,64,64),haloMat);
scene.add(halo);

// Clouds layer
let clouds=null;
if(!isLow){
  const cloudTex=mkClouds();
  cloudTex.wrapS=cloudTex.wrapT=THREE.RepeatWrapping;
  cloudTex.minFilter=THREE.LinearMipmapLinearFilter;
  cloudTex.magFilter=THREE.LinearFilter;
  cloudTex.generateMipmaps=true;
  cloudTex.anisotropy=maxAniso;
  if('encoding' in cloudTex)cloudTex.encoding=THREE.sRGBEncoding;
  cloudTex.needsUpdate=true;
  clouds=new THREE.Mesh(
    new THREE.SphereGeometry(2.052,isLow?64:128,isLow?64:128),
    new THREE.MeshPhongMaterial({map:cloudTex,transparent:true,opacity:.42,depthWrite:false,shininess:8,specular:new THREE.Color(.12,.14,.18)})
  );
  scene.add(clouds);
}


// ─ MOON — orbiting body ─
function mkMoon(){
  const S=isLow?256:512;
  const cv=document.createElement('canvas');cv.width=S;cv.height=S;
  const c=cv.getContext('2d');

  // ── 1. Highland regolith base — photometrically accurate gradient ──
  // Moon surface: bright highlands (top/right) to darker limb
  const bg=c.createRadialGradient(S*.44,S*.40,0,S*.5,S*.5,S*.53);
  bg.addColorStop(0,'#d6d3ca');   // bright central highlands
  bg.addColorStop(.28,'#c2bfb6');
  bg.addColorStop(.52,'#a8a5a0');
  bg.addColorStop(.74,'#8a8780');
  bg.addColorStop(.90,'#6e6c66');
  bg.addColorStop(1,'#282622');   // dark limb (absorption)
  c.fillStyle=bg; c.beginPath(); c.arc(S/2,S/2,S/2,0,Math.PI*2); c.fill();

  // ── 2. Regolith grain — fine high-frequency noise (dust layer) ──
  for(let i=0;i<6000;i++){
    const x=H2(i*3.713)*S, y=H2(i*5.131)*S;
    // Check inside circle
    const dx=x-S/2, dy=y-S/2;
    if(dx*dx+dy*dy>(S*.49)*(S*.49)) continue;
    const v=(H2(i*2.317)-.5)*.12;
    // Vary grain color slightly by position (highlands brighter)
    const distFrac=Math.sqrt(dx*dx+dy*dy)/(S*.5);
    const base=218-distFrac*80;
    c.fillStyle=`rgba(${(base+v*80)|0},${(base-2+v*75)|0},${(base-8+v*65)|0},${Math.abs(v)*.68})`;
    c.fillRect(x,y,.8,.8);
  }

  // ── 3. Maria (dark basaltic plains) — realistic placement of near-side maria ──
  function mare(cx,cy,rx,ry,rot,alpha,darkness){
    c.save(); c.translate(cx*S,cy*S); c.rotate(rot||0); c.scale(1,ry/Math.max(rx,1));

    // Base fill — dark basalt (not black, brownish-grey)
    const gBase=c.createRadialGradient(rx*.22,ry*.12,0,0,0,rx);
    const dc=`rgba(${38+darkness*8|0},${36+darkness*8|0},${32+darkness*8|0},`;
    gBase.addColorStop(0,dc+(alpha*.94)+')');
    gBase.addColorStop(.55,dc+(alpha*.76)+')');
    gBase.addColorStop(.82,dc+(alpha*.38)+')');
    gBase.addColorStop(1,'transparent');
    c.beginPath(); c.arc(0,0,rx,0,Math.PI*2); c.fillStyle=gBase; c.fill();

    // Basalt texture micro-variation
    for(let i=0;i<120;i++){
      const mx=H2(i*7.131)*rx*2-rx, my=H2(i*9.317)*rx*2-rx;
      if(mx*mx+my*my<rx*rx*.68){
        const tc=28+H2(i*3.131)*24|0;
        c.fillStyle=`rgba(${tc},${tc-2|0},${tc-6|0},${H2(i*2.917)*.22})`;
        c.fillRect(cx*0+mx,cy*0+my,1.5,1.5);// offset relative coords
      }
    }
    c.restore();

    // Wrinkle ridges at maria edges (subtle lighter arcs)
    const px=cx*S, py=cy*S;
    c.globalAlpha=.12;
    c.strokeStyle='rgba(168,165,155,.5)';
    c.lineWidth=.7;
    c.beginPath();
    c.ellipse(px,py,rx*.72*(S/512),ry*.72*(S/512),rot||0,0,Math.PI*1.4);
    c.stroke();
    c.globalAlpha=1;
  }

  // Near-side maria — scientifically accurate positions and sizes
  mare(.298,.388, S*.210,S*.150,-.16,.88,1.0); // Mare Imbrium (largest, NW quadrant)
  mare(.508,.332, S*.118,S*.095, .09,.80,0.8); // Mare Serenitatis (NE)
  mare(.558,.462, S*.138,S*.098, .06,.82,0.9); // Mare Tranquillitatis (center-E)
  mare(.228,.468, S*.232,S*.158, .12,.84,1.2); // Oceanus Procellarum (huge, W)
  mare(.418,.562, S*.108,S*.078, .13,.76,0.7); // Mare Nubium (SW center)
  mare(.720,.392, S*.078,S*.058,-.09,.72,0.6); // Mare Crisium (isolated, far E)
  mare(.608,.608, S*.068,S*.048, .19,.66,0.5); // Mare Fecunditatis (SE)
  mare(.468,.288, S*.048,S*.038,-.08,.64,0.5); // Mare Vaporum (small, center N)
  mare(.368,.308, S*.048,S*.038, .04,.60,0.4); // Mare Insularum (connecting)
  mare(.252,.338, S*.052,S*.038, .06,.62,0.5); // Sinus Aestuum

  // ── 4. Crater system — physically accurate morphology ──
  // Small craters: simple bowl with rim
  // Medium: raised rim + flat floor + central peak option
  // Large (>15px): wall terracing, multiple rings
  function crater(cx,cy,r,depth,rayCount,ageFactor){
    // ageFactor: 1.0=fresh sharp, 0.3=heavily degraded
    const px=cx*S, py=cy*S;
    const rimW=r*(1.15+ageFactor*.25); // fresh craters have sharper rims

    // Ejecta rays (only fresh, large craters)
    if(rayCount>0&&ageFactor>.65){
      for(let i=0;i<rayCount;i++){
        const ang=i*Math.PI*2/rayCount+H2(cx*97.3+i)*.52+H2(cy*83.7)*.38;
        const len=r*(2.8+H2(cy*101+i)*2.8+ageFactor);
        const rayW=r*.22*(ageFactor);
        const rg=c.createLinearGradient(
          px+Math.cos(ang)*r,py+Math.sin(ang)*r,
          px+Math.cos(ang)*len,py+Math.sin(ang)*len);
        rg.addColorStop(0,`rgba(222,218,210,${.18*ageFactor})`);
        rg.addColorStop(.4,`rgba(215,212,204,${.09*ageFactor})`);
        rg.addColorStop(1,'transparent');
        c.strokeStyle=rg; c.lineWidth=rayW;
        c.beginPath();
        c.moveTo(px+Math.cos(ang)*r,py+Math.sin(ang)*r);
        c.lineTo(px+Math.cos(ang)*len,py+Math.sin(ang)*len);
        c.stroke();
        // Secondary rays (branching)
        if(H2(cx*37+i)>.6){
          const sAng=ang+H2(cy*41+i)*.38-.19;
          const sLen=len*.55;
          c.lineWidth=rayW*.5;
          c.beginPath();
          c.moveTo(px+Math.cos(ang)*r*1.4,py+Math.sin(ang)*r*1.4);
          c.lineTo(px+Math.cos(sAng)*sLen,py+Math.sin(sAng)*sLen);
          c.stroke();
        }
      }
    }

    // Continuous ejecta blanket (halo of bright material)
    if(ageFactor>.4){
      const ejecta=c.createRadialGradient(px,py,r*.85,px,py,rimW*1.8);
      ejecta.addColorStop(0,'transparent');
      ejecta.addColorStop(.3,`rgba(205,202,195,${depth*.24*ageFactor})`);
      ejecta.addColorStop(.7,`rgba(198,195,188,${depth*.12*ageFactor})`);
      ejecta.addColorStop(1,'transparent');
      c.fillStyle=ejecta; c.beginPath(); c.arc(px,py,rimW*1.8,0,Math.PI*2); c.fill();
    }

    // Outer rim ring — bright raised wall
    const rim=c.createRadialGradient(px,py,r*.72,px,py,rimW*1.08);
    rim.addColorStop(0,'transparent');
    rim.addColorStop(.38,`rgba(215,212,202,${depth*.58*ageFactor})`);
    rim.addColorStop(.65,`rgba(208,205,196,${depth*.34*ageFactor})`);
    rim.addColorStop(.82,`rgba(195,192,184,${depth*.18*ageFactor})`);
    rim.addColorStop(1,'transparent');
    c.fillStyle=rim; c.beginPath(); c.arc(px,py,rimW*1.08,0,Math.PI*2); c.fill();

    // Shadow interior (anisotropic — darker on sunward side lower wall)
    // Sun from upper-left: shadow in lower-right of interior
    const shadowOff=r*.18;
    const interior=c.createRadialGradient(
      px-shadowOff*.8,py-shadowOff*.6, 0,
      px+shadowOff*.5,py+shadowOff*.4, r*.82);
    interior.addColorStop(0,`rgba(14,12,10,${depth*.88})`);
    interior.addColorStop(.35,`rgba(22,20,17,${depth*.68})`);
    interior.addColorStop(.65,`rgba(34,32,28,${depth*.42})`);
    interior.addColorStop(1,'transparent');
    c.fillStyle=interior; c.beginPath(); c.arc(px,py,r*.82,0,Math.PI*2); c.fill();

    // Flat floor for larger craters (> 5% of S)
    if(r>S*.046){
      const floor=c.createRadialGradient(px,py,0,px,py,r*.52);
      floor.addColorStop(0,`rgba(56,54,50,${depth*.52})`);
      floor.addColorStop(.7,`rgba(44,42,38,${depth*.36})`);
      floor.addColorStop(1,'transparent');
      c.fillStyle=floor; c.beginPath(); c.arc(px,py,r*.52,0,Math.PI*2); c.fill();

      // Wall terracing (concentric rings inside large craters)
      for(let t=1;t<=2;t++){
        const tr=r*(1-t*.24);
        c.strokeStyle=`rgba(148,146,140,${depth*.18})`;
        c.lineWidth=1; c.beginPath(); c.arc(px,py,tr,0,Math.PI*2); c.stroke();
      }
    }

    // Central peak (complex craters > 8% of S)
    if(r>S*.032&&ageFactor>.55){
      const cpR=r*.12+r*.06*ageFactor;
      const cpG=c.createRadialGradient(px,py,0,px,py,cpR);
      cpG.addColorStop(0,`rgba(205,202,194,${depth*.62*ageFactor})`);
      cpG.addColorStop(.6,`rgba(185,182,174,${depth*.32*ageFactor})`);
      cpG.addColorStop(1,'transparent');
      c.fillStyle=cpG; c.beginPath(); c.arc(px,py,cpR,0,Math.PI*2); c.fill();
    }
  }

  // ── Main named craters ──
  // [cx, cy, radius_fraction, depth, rays, age(0-1)]
  [
    // TYCHO — very fresh, most prominent rays
    [.622,.748,S*.062,.92,14,.95],
    // COPERNICUS — large, fresh, major rays
    [.386,.302,S*.054,.88,12,.88],
    // KEPLER — medium, rays
    [.284,.306,S*.040,.80,10,.82],
    // ARISTARCHUS — very bright, fresh
    [.212,.324,S*.032,.84, 8,.90],
    // PLATO — large flooded (old, dark flat floor)
    [.318,.226,S*.040,.42, 0,.32],
    // CLAVIUS — large ancient (degraded)
    [.498,.788,S*.058,.38, 0,.28],
    // SCHICKARD — ancient flooded
    [.242,.668,S*.048,.36, 0,.25],
    // GRIMALDI — very dark floor (basaltic fill)
    [.148,.468,S*.040,.44, 0,.30],
    // PETAVIUS — medium fresh
    [.748,.648,S*.038,.72, 6,.72],
    // THEOPHILUS — sharp rim overlapping older crater
    [.598,.548,S*.034,.78, 0,.78],
    // LANGRENUS — east limb
    [.812,.468,S*.034,.70, 5,.72],
    // PYTHEAS / medium
    [.408,.282,S*.026,.64, 0,.70],
    // ERATOSTHENES
    [.440,.308,S*.028,.66, 4,.68],
    // BULLIALDUS
    [.408,.548,S*.024,.62, 0,.65],
    // CATHARINA
    [.626,.572,S*.022,.60, 0,.62],
    // CYRILLUS
    [.612,.560,S*.022,.60, 0,.62],
    // HIPPARCHUS (ancient, degraded)
    [.518,.438,S*.032,.28, 0,.22],
    // ALBATEGNIUS
    [.540,.458,S*.030,.34, 0,.28],
    // PTOLEMAEUS (vast, old)
    [.488,.468,S*.044,.26, 0,.20],
    // ALPHONSUS
    [.488,.498,S*.032,.30, 0,.24],
    // ARZACHEL
    [.488,.524,S*.024,.52, 0,.52],
    // STÖFLER (ancient)
    [.548,.618,S*.034,.28, 0,.22],
    // WALTER
    [.514,.586,S*.028,.32, 0,.25],
    // PICCOLOMINI
    [.678,.618,S*.022,.64, 4,.66],
    // FRACASTORIUS (flooded bay)
    [.628,.638,S*.028,.34, 0,.28],
    // FURNERIUS
    [.776,.668,S*.026,.58, 3,.58],
    // STEVINUS
    [.736,.676,S*.020,.60, 3,.62],
    // RHEITA
    [.696,.698,S*.018,.54, 0,.55],
    // SNELLIUS
    [.756,.654,S*.018,.56, 0,.56],
    // HUMBOLT (E limb)
    [.844,.518,S*.030,.62, 4,.62],
  ].forEach(args=>crater(...args));

  // ── Small crater field — statistically distributed ──
  for(let i=0;i<180;i++){
    const mx=H2(i*11.317)*S, my=H2(i*13.713)*S;
    const dx=mx-S/2, dy=my-S/2;
    if(dx*dx+dy*dy>(S*.46)*(S*.46)) continue;
    const r=H2(i*7.317)*4.8+1.2;
    const age=H2(i*3.71)*.7+.3;
    const dep=H2(i*5.13)*.5+.3;
    // Simple small crater
    const rim=c.createRadialGradient(mx-r*.15,my-r*.12,0,mx,my,r*1.12);
    rim.addColorStop(0,'transparent');
    rim.addColorStop(.42,`rgba(205,202,196,${dep*.40*age})`);
    rim.addColorStop(.72,`rgba(195,192,186,${dep*.22*age})`);
    rim.addColorStop(1,'transparent');
    c.fillStyle=rim; c.beginPath(); c.arc(mx,my,r*1.12,0,Math.PI*2); c.fill();
    const ic=c.createRadialGradient(mx+r*.14,my+r*.10,0,mx,my,r*.78);
    ic.addColorStop(0,`rgba(12,10,8,${dep*.78})`);
    ic.addColorStop(.6,`rgba(28,26,22,${dep*.45})`);
    ic.addColorStop(1,'transparent');
    c.fillStyle=ic; c.beginPath(); c.arc(mx,my,r*.78,0,Math.PI*2); c.fill();
  }

  // ── 5. Secondary crater chains ──
  for(let chain=0;chain<5;chain++){
    const startX=H2(chain*17.3)*S, startY=H2(chain*23.7)*S;
    const ang=H2(chain*7.1)*Math.PI*2;
    const len=S*(H2(chain*11.3)*.25+.12);
    const nSec=5+chain*2;
    for(let i=0;i<nSec;i++){
      const t=i/nSec;
      const scx=startX+Math.cos(ang)*len*t;
      const scy=startY+Math.sin(ang)*len*t;
      const dx=scx-S/2, dy=scy-S/2;
      if(dx*dx+dy*dy>(S*.47)*(S*.47)) continue;
      const sr=H2(chain*33+i)*2.2+.8;
      const sg=c.createRadialGradient(scx,scy,0,scx,scy,sr*1.1);
      sg.addColorStop(0,'rgba(18,16,13,.65)');
      sg.addColorStop(.7,'rgba(192,190,184,.18)');
      sg.addColorStop(1,'transparent');
      c.fillStyle=sg; c.beginPath(); c.arc(scx,scy,sr*1.1,0,Math.PI*2); c.fill();
    }
  }

  // ── 6. Lunar surface color variations ──
  // Bright ray blankets around Tycho/Copernicus
  [[.622,.748,S*.18,.08,'rgba(225,222,215,'],[.386,.302,S*.14,.06,'rgba(218,215,208,']].forEach(([cx,cy,r,a,col])=>{
    const rg=c.createRadialGradient(cx*S,cy*S,r*.5,cx*S,cy*S,r);
    rg.addColorStop(0,'transparent');
    rg.addColorStop(.3,col+a+')');
    rg.addColorStop(1,'transparent');
    c.fillStyle=rg; c.beginPath(); c.arc(cx*S,cy*S,r,0,Math.PI*2); c.fill();
  });

  // ── 7. Limb darkening — accurate Hapke-model approximation ──
  c.save(); c.translate(S/2,S/2);
  const limb=c.createRadialGradient(0,0,S*.22,0,0,S*.515);
  limb.addColorStop(0,'rgba(0,0,0,0)');
  limb.addColorStop(.55,'rgba(0,0,0,.06)');
  limb.addColorStop(.75,'rgba(0,0,0,.18)');
  limb.addColorStop(.90,'rgba(0,0,0,.44)');
  limb.addColorStop(1,'rgba(0,0,0,.76)');
  c.fillStyle=limb; c.beginPath(); c.arc(0,0,S*.515,0,Math.PI*2); c.fill();
  c.restore();

  // ── 8. Phase shading — realistic terminator (sun from upper-left) ──
  // Very subtle — main terminator is handled by shader lighting
  // This adds the "bright limb" direction hint in texture
  c.save(); c.translate(S*.5,S*.5);
  const sunShine=c.createRadialGradient(-S*.15,-S*.12,0,-S*.15,-S*.12,S*.65);
  sunShine.addColorStop(0,'rgba(255,252,245,.04)'); // subtle highlight upper-left
  sunShine.addColorStop(.5,'rgba(255,252,245,.015)');
  sunShine.addColorStop(1,'rgba(0,0,0,0)');
  c.fillStyle=sunShine; c.beginPath(); c.arc(0,0,S*.515,0,Math.PI*2); c.fill();
  c.restore();

  return new THREE.CanvasTexture(cv);
}
// Moon normal map — generated from moon texture luminance
function mkMoonNormal(){
  const S=isLow?128:256;
  const cv=document.createElement('canvas');cv.width=S;cv.height=S;
  const c=cv.getContext('2d');
  // Neutral normal (pointing up) encoded as RGB(128,128,255)
  c.fillStyle='rgb(128,128,255)';c.fillRect(0,0,S,S);
  // Sample moon texture to derive normals — major crater rims as bumps
  // Crater rims: encode outward normal (bright rim = +Z component)
  // [cx, cy, r, strength]
  const craterNorms=[
    [.622,.748,S*.062,.85],[.386,.302,S*.054,.80],[.284,.306,S*.040,.75],
    [.212,.324,S*.032,.78],[.498,.788,S*.058,.62],[.598,.548,S*.034,.72],
    [.748,.648,S*.038,.70],[.212,.324,S*.032,.78],
  ];
  craterNorms.forEach(([cx,cy,r,str])=>{
    const px=cx*S,py=cy*S;
    // Rim — outward normals (reddish-greenish tint = +X/-Y bias)
    for(let ang=0;ang<Math.PI*2;ang+=.08){
      const rx=Math.cos(ang),ry=Math.sin(ang);
      const nx=128+rx*str*60|0, ny=128+ry*str*60|0;
      c.fillStyle=`rgb(${Math.max(0,Math.min(255,nx))},${Math.max(0,Math.min(255,ny))},180)`;
      c.fillRect(px+rx*r*.88,py+ry*r*.88,2,2);
    }
    // Interior — inward slope normals
    const ig=c.createRadialGradient(px,py,0,px,py,r*.75);
    ig.addColorStop(0,'rgba(128,128,200,.6)');
    ig.addColorStop(.5,'rgba(128,128,220,.3)');
    ig.addColorStop(1,'transparent');
    c.fillStyle=ig;c.beginPath();c.arc(px,py,r*.75,0,Math.PI*2);c.fill();
  });
  return new THREE.CanvasTexture(cv);
}

