// Film grain — tiled 128×128 noise tile (upscaled) to avoid per-pixel CPU cost
const gCv=document.getElementById('gCv'),gCtx=gCv.getContext('2d');
function rsGrain(){gCv.width=W();gCv.height=H();}rsGrain();
let gf=0;
const _GT=128;// grain tile size
const _gTile=(()=>{const cv=document.createElement('canvas');cv.width=cv.height=_GT;return cv;})();
const _gCtx=_gTile.getContext('2d');
const _gImg=_gCtx.createImageData(_GT,_GT);
function grain(){
  gf++;
  if(isMob)return;// skip on mobile — heavy per frame
  if(gf%(isLow?8:4)!==0)return;// throttle: every 4 frames desktop, 8 on low-end
  const d=_gImg.data;
  for(let i=0;i<d.length;i+=4){const v=Math.random()*255|0;d[i]=d[i+1]=d[i+2]=v;d[i+3]=14+Math.random()*16|0;}
  _gCtx.putImageData(_gImg,0,0);
  const W2=gCv.width,H2=gCv.height;
  for(let ty=0;ty<H2;ty+=_GT)for(let tx=0;tx<W2;tx+=_GT)gCtx.drawImage(_gTile,tx,ty);
}

// Chromatic aberration canvas
const chCv=document.getElementById('chCv'),chCtx=chCv.getContext('2d');
let chTill=0;
function rsChroma(){chCv.width=W();chCv.height=H();}rsChroma();
function fireChroma(ms){chTill=Date.now()+ms;}
function drawChroma(){
  const now=Date.now();
  if(now>chTill){chCtx.clearRect(0,0,chCv.width,chCv.height);return;}
  const I=Math.min(1,(chTill-now)/800);if(I<.02)return;
  const shakeBoost=shk?shkS*1.8:1;const shift=Math.floor(4+shakeBoost*4);
  chCtx.clearRect(0,0,chCv.width,chCv.height);
  chCtx.globalAlpha=I*(shk?.15:.09);
  chCtx.fillStyle='rgba(255,0,60,1)';chCtx.fillRect(shift,0,chCv.width,chCv.height);
  chCtx.fillStyle='rgba(0,255,210,1)';chCtx.fillRect(-shift,0,chCv.width,chCv.height);
  chCtx.globalAlpha=1;
}

