function showT(txt,cls=[],dur=3000,sub=''){
  return new Promise(res=>{
    // ── FADE OUT current text smoothly ──
    mt.style.opacity='0';
    stEl.style.opacity='0';
    // Brief breathe gap — long enough for CSS transition (1.5s) to nearly complete
    // but short to keep rhythm tight. 320ms = starts fading before fully gone,
    // overlapping = cinematic dissolve feel, not a hard blink.
    setTimeout(()=>{
      mt.className='';
      mt.textContent=txt;
      // Slight upward arrival — reset transform then let CSS handle it
      mt.style.transform='translateY(8px)';
      mt.style.transition='opacity 1.2s ease, transform 1.1s cubic-bezier(.22,1,.36,1)';
      cls.forEach(c=>mt.classList.add(c));
      // Small tick to let browser register the starting state
      requestAnimationFrame(()=>{
        requestAnimationFrame(()=>{
          mt.style.opacity='1';
          mt.style.transform='translateY(0)';
        });
      });
      // Sub-text enters after main is fully visible
      if(sub){
        stEl.textContent=sub;
        stEl.style.opacity='0';
        setTimeout(()=>stEl.style.opacity='1',680);
      }
      // Hold for dur, then fade out
      setTimeout(()=>{
        mt.style.opacity='0';
        mt.style.transform='translateY(-5px)';
        stEl.style.opacity='0';
        // Gap between fade-out start and next text starts arriving
        setTimeout(res,900);
      },dur);
    },280);
  });
}
function pinT(txt,cls=[],sub=''){
  mt.style.opacity='0';stEl.style.opacity='0';
  setTimeout(()=>{
    mt.className='';mt.textContent=txt;
    mt.style.transform='translateY(8px)';
    mt.style.transition='opacity 1.2s ease, transform 1.1s cubic-bezier(.22,1,.36,1)';
    cls.forEach(c=>mt.classList.add(c));
    requestAnimationFrame(()=>requestAnimationFrame(()=>{
      mt.style.opacity='1';mt.style.transform='translateY(0)';
    }));
    if(sub){stEl.textContent=sub;stEl.style.opacity='0';
      setTimeout(()=>stEl.style.opacity='1',600);}
  },280);
}
