/* ─ CAMERA ORBIT SYSTEM ─ */
let camOrbit=false,camOrbitAngle=0,camOrbitSpeed=0.00032,camOrbitR=0.28;
function startOrbit(speed=0.00032,r=0.28){camOrbit=true;camOrbitSpeed=speed;camOrbitR=r;}
function stopOrbit(){camOrbit=false;}

/* ─ DEEP OCEAN SIGNAL ─ */
let deepGlowAlpha=0,deepGlowTarget=0;
let signal2Active=false,signal2Ph=0;
function setOcean(v,dur=1800){
  const start=atmMat.uniforms.uOcean.value,t0=Date.now();
  deepGlowTarget=v;
  const step=()=>{const p=Math.min(1,(Date.now()-t0)/dur);
    atmMat.uniforms.uOcean.value=start+(v-start)*p;
    deepGlowAlpha=start+(v-start)*p;
    if(p<1)requestAnimationFrame(step);};step();
  const dg=document.getElementById('deepGlow');
  const op=document.getElementById('oceanPulse');
  if(dg)dg.classList.toggle('show',v>0.05);
  if(op)op.classList.toggle('show',v>0.1);
}

/* ─ WARM GLITCH (gold-green) ─ */
function fireWarmGlitch(){
  const g=document.getElementById('glitchWarm');
  if(!g)return;
  g.classList.remove('on');void g.offsetWidth;g.classList.add('on');
  setTimeout(()=>g.classList.remove('on'),560);
}

/* ─ DUAL SCAN RING (upward, from ocean floor) ─ */
let dualRingAlpha=0,dualRingR=0,dualRingActive=false;
function triggerDualRing(){dualRingActive=true;dualRingAlpha=1;dualRingR=0;}
function drawDualRing(){
  // Draw on the overlayCanvas — upward expanding ring (bottom of screen origin)
  if(!dualRingActive&&dualRingAlpha<=0)return;
  const cx=ovCv.width/2,cy=ovCv.height*.72;// origin lower
  if(dualRingActive){
    dualRingR+=2.4;
    if(dualRingR>Math.max(ovCv.width,ovCv.height)*1.2){dualRingActive=false;dualRingAlpha=0;return;}
  }
  dualRingAlpha=Math.max(0,dualRingAlpha-.006);
  ovCtx.beginPath();
  ovCtx.arc(cx,cy,dualRingR,0,Math.PI*2);
  ovCtx.strokeStyle=`rgba(0,210,160,${dualRingAlpha*.32})`;
  ovCtx.lineWidth=1.2;ovCtx.stroke();
  ovCtx.beginPath();
  ovCtx.arc(cx,cy,dualRingR*.55,0,Math.PI*2);
  ovCtx.strokeStyle=`rgba(0,180,160,${dualRingAlpha*.12})`;
  ovCtx.lineWidth=.8;ovCtx.stroke();
}

/* ─ SECOND BIO SIGNAL (ancient, slower) ─ */
// Injected into drawBio() via flag signal2Active
function drawSignal2(ctx,w,h){
  if(!signal2Active)return;
  ctx.beginPath();
  for(let x=0;x<w;x++){
    // Much slower wave — ancient rhythm
    const y=h*.5+Math.sin(x*.018+signal2Ph)*(h*.28*(0.5+Math.sin(x*.006+signal2Ph*.3)*.5));
    x===0?ctx.moveTo(x,y):ctx.lineTo(x,y);}
  const gs=ctx.createLinearGradient(0,0,w,0);
  gs.addColorStop(0,'transparent');
  gs.addColorStop(.15,'rgba(0,210,160,.35)');
  gs.addColorStop(.85,'rgba(0,210,160,.35)');
  gs.addColorStop(1,'transparent');
  ctx.strokeStyle=gs;ctx.lineWidth=.9;ctx.stroke();
  signal2Ph+=.006;// 5× slower than human wave
}

