/* ─ CHAPTER III AUDIO ─ */
let ancientDrone=null,ancientGain=null;// persistent ancient tone
function playC3Audio(sceneNum){
  if(!aC||!mG)return;
  try{
    if(sceneNum===25){// anomaly — existing drone shifts + new sub-bass
      // Detune existing drones down a semitone
      dOscs.forEach(o=>{try{o.frequency.linearRampToValueAtTime(o.frequency.value*.944,aC.currentTime+4);}catch(e){console.warn("[ascension]",e);}});
      // New low anomaly pulse
      const ab=aC.createOscillator(),ag=aC.createGain();
      ab.type='sine';ab.frequency.value=18.5;// standing wave frequency
      ag.gain.setValueAtTime(0,aC.currentTime);ag.gain.linearRampToValueAtTime(.18,aC.currentTime+3);
      ag.gain.linearRampToValueAtTime(.08,aC.currentTime+12);
      ab.connect(ag).connect(mG);ab.start();ab.stop(aC.currentTime+16);
      ancientDrone=ab;ancientGain=ag;}

    if(sceneNum===26){// the sleeper — 18Hz standing wave, glass harmonic
      // Deep 18Hz pulse (felt not heard)
      const sw=aC.createOscillator(),sg=aC.createGain();
      sw.type='sine';sw.frequency.value=18;
      sg.gain.setValueAtTime(.22,aC.currentTime);sg.gain.linearRampToValueAtTime(.12,aC.currentTime+8);
      sw.connect(sg).connect(mG);sw.start();sw.stop(aC.currentTime+14);
      // Glass harmonic shimmer (high partials)
      [880,1320,1760,2200].forEach((f,i)=>{
        const o=aC.createOscillator(),g=aC.createGain();
        o.type='sine';o.frequency.value=f;
        // Vibrato LFO
        const lf=aC.createOscillator(),lg=aC.createGain();
        lf.frequency.value=4.8+i*.4;lg.gain.value=f*.008;
        lf.connect(lg);lg.connect(o.frequency);lf.start();
        g.gain.setValueAtTime(0,aC.currentTime+i*.3);
        g.gain.linearRampToValueAtTime(.008,aC.currentTime+i*.3+.8);
        g.gain.linearRampToValueAtTime(0,aC.currentTime+8+i);
        o.connect(g).connect(mG);o.start(aC.currentTime+i*.3);
        o.stop(aC.currentTime+9+i);lf.stop(aC.currentTime+9+i);});}

    if(sceneNum===27){// recognition — two drones find brief harmonic
      // A perfect fifth between the two drone groups
      [55,82.5].forEach((f,i)=>{
        const o=aC.createOscillator(),g=aC.createGain();
        o.type='sine';o.frequency.value=f;
        o.detune.value=(i===0?0:2);// tiny detune for warmth
        g.gain.setValueAtTime(0,aC.currentTime);
        g.gain.linearRampToValueAtTime(.055,aC.currentTime+2.5);
        g.gain.linearRampToValueAtTime(0,aC.currentTime+6.5);
        o.connect(g).connect(mG);o.start();o.stop(aC.currentTime+7);});}

    if(sceneNum===28){// inheritance — singing bowl hybrid
      [174,261,392,523].forEach((f,i)=>{
        const o=aC.createOscillator(),g=aC.createGain();
        o.type='triangle';o.frequency.value=f;
        // Slow attack like a mallet strike
        g.gain.setValueAtTime(0,aC.currentTime+i*.4);
        g.gain.linearRampToValueAtTime(.028,aC.currentTime+i*.4+.35);
        g.gain.exponentialRampToValueAtTime(.008,aC.currentTime+i*.4+3.5);
        g.gain.linearRampToValueAtTime(0,aC.currentTime+i*.4+6);
        o.connect(g).connect(mG);o.start(aC.currentTime+i*.4);o.stop(aC.currentTime+i*.4+6);});}

    if(sceneNum===29){// two minds — dual drone weave
      [[44,1],[55,.85],[82.5,.7]].forEach(([f,vol],i)=>{
        const o=aC.createOscillator(),g=aC.createGain();
        o.type='sine';o.frequency.value=f;
        o.detune.value=(Math.random()-.5)*6;
        g.gain.setValueAtTime(0,aC.currentTime);
        g.gain.linearRampToValueAtTime(vol*.06,aC.currentTime+2+i);
        g.gain.linearRampToValueAtTime(vol*.03,aC.currentTime+10);
        o.connect(g).connect(mG);o.start();o.stop(aC.currentTime+14);});}

    if(sceneNum===30){// patient sustained chord — no resolution
      [36,54,81].forEach((f,i)=>{
        const o=aC.createOscillator(),g=aC.createGain();
        o.type='sine';o.frequency.value=f;
        o.detune.value=(Math.random()-.5)*8;
        g.gain.setValueAtTime(0,aC.currentTime);
        g.gain.linearRampToValueAtTime(.09,aC.currentTime+4);
        g.gain.setValueAtTime(.09,aC.currentTime+9);
        g.gain.linearRampToValueAtTime(0,aC.currentTime+14);
        o.connect(g).connect(mG);o.start();o.stop(aC.currentTime+15);});}

    if(sceneNum===31){// quietest moment — one high tone + 18Hz only
      mG.gain.linearRampToValueAtTime(isMob?.18:.22,aC.currentTime+1.5);
      const ho=aC.createOscillator(),hg=aC.createGain();
      ho.type='sine';ho.frequency.value=1320;
      hg.gain.setValueAtTime(0,aC.currentTime);
      hg.gain.linearRampToValueAtTime(.012,aC.currentTime+2);
      hg.gain.linearRampToValueAtTime(0,aC.currentTime+18);
      ho.connect(hg).connect(mG);ho.start();ho.stop(aC.currentTime+19);}

    if(sceneNum===32){// resolution — one clean major chord
      [130,164,196,261].forEach((f,i)=>{
        const o=aC.createOscillator(),g=aC.createGain();
        o.type='triangle';o.frequency.value=f;
        g.gain.setValueAtTime(0,aC.currentTime+i*.06);
        g.gain.linearRampToValueAtTime(.035,aC.currentTime+i*.06+.4);
        g.gain.linearRampToValueAtTime(.018,aC.currentTime+4);
        g.gain.linearRampToValueAtTime(0,aC.currentTime+8);
        o.connect(g).connect(mG);o.start(aC.currentTime+i*.06);o.stop(aC.currentTime+8);});}

    if(sceneNum===33){// first contact reflection — slow ascending arpeggio
      [82,110,131,165,220].forEach((f,i)=>{
        const o=aC.createOscillator(),g=aC.createGain();
        o.type='sine';o.frequency.value=f;
        g.gain.setValueAtTime(0,aC.currentTime+i*.8);
        g.gain.linearRampToValueAtTime(.022,aC.currentTime+i*.8+.6);
        g.gain.linearRampToValueAtTime(0,aC.currentTime+i*.8+5);
        o.connect(g).connect(mG);o.start(aC.currentTime+i*.8);o.stop(aC.currentTime+i*.8+6);});}

    if(sceneNum===34){// the translation — question-like rising interval
      [[110,1.0],[165,.7],[220,.5]].forEach(([f,v],i)=>{
        const o=aC.createOscillator(),g=aC.createGain();
        o.type='sine';o.frequency.value=f;
        o.frequency.linearRampToValueAtTime(f*1.5,aC.currentTime+3);// rise — unresolved question
        g.gain.setValueAtTime(0,aC.currentTime+i*.3);
        g.gain.linearRampToValueAtTime(.028*v,aC.currentTime+i*.3+.5);
        g.gain.linearRampToValueAtTime(0,aC.currentTime+i*.3+7);
        o.connect(g).connect(mG);o.start(aC.currentTime+i*.3);o.stop(aC.currentTime+i*.3+8);});}

    if(sceneNum===35){// becoming — slow convergence of two drone lines
      [[44,.55],[66,.45],[99,.35],[148,.28]].forEach(([f,v],i)=>{
        const o=aC.createOscillator(),g=aC.createGain();
        o.type='sine';o.frequency.value=f;
        o.detune.value=(i%2===0?8:-8);// slight beating between pairs
        g.gain.setValueAtTime(0,aC.currentTime+i*.5);
        g.gain.linearRampToValueAtTime(v*.08,aC.currentTime+i*.5+2);
        g.gain.linearRampToValueAtTime(v*.04,aC.currentTime+10);
        g.gain.linearRampToValueAtTime(0,aC.currentTime+16);
        o.connect(g).connect(mG);o.start(aC.currentTime+i*.5);o.stop(aC.currentTime+17);});}

  }catch(e){console.warn('C3 audio:',e);}}

/* ─ SHOW CHAPTER III PART CARD ─ */
function showC3Card(cb){
  const pc=document.getElementById('partCard3');
  if(!pc)return cb&&cb();
  pc.style.display='flex';
  requestAnimationFrame(()=>{pc.classList.add('show');});
  setTimeout(()=>{
    pc.classList.add('out');
    setTimeout(()=>{pc.style.display='none';if(cb)cb();},1600);
  },4500);
}

